DELETE FROM public.workflow_templates WHERE category = 'b2000001-0001-4000-8000-000000000046::Australia';
INSERT INTO public.workflow_templates (name, country, category, version, items, groups)
VALUES ('Australia Work Holiday — Document binder', 'Australia', 'b2000001-0001-4000-8000-000000000046::Australia', 1, '[{"id":"valid_passport_from_eligible_working_holiday_cou","name":"Valid passport from eligible Working Holiday country","mandatory":true,"notes":"417 for most partner countries (UK, Canada, Japan, etc.). 462 for USA, India, China, Vietnam, and others — verify Home Affairs list. India is 462 only (not 417)."},{"id":"applicant_age_within_limit_generally_18_30_up_to","name":"Applicant age within limit (generally 18–30; up to 35 for select countries)","mandatory":true,"notes":"Age is assessed at time of application. Confirm subclass 417 vs 462 rules for passport country."},{"id":"first_working_holiday_maker_whm_visa_no_prior_wh","name":"First Working Holiday Maker (WHM) visa — no prior WHM held","mandatory":true,"notes":"Second WHM may be possible only if client completed specified work in regional Australia on first WHM — separate pathway."},{"id":"valid_passport_bio_page_previous_australian_visa","name":"Valid passport bio page + previous Australian visa pages (if any)","mandatory":true,"notes":"Colour scan, all corners visible, no glare."},{"id":"digital_photo_per_home_affairs_immiaccount_speci","name":"Digital photo per Home Affairs / ImmiAccount specifications","mandatory":true},{"id":"not_accompanied_by_dependent_children_at_any_tim","name":"Not accompanied by dependent children at any time during stay","mandatory":true},{"id":"immiaccount_created_and_online_whm_application_s","name":"ImmiAccount created and online WHM application started","mandatory":true,"notes":"Subclass 417 or 462 selected correctly for passport country."},{"id":"462_ballot_registration_completed_if_required_in","name":"462 ballot registration completed if required (India, China, Vietnam)","mandatory":true,"notes":"Mandatory pre-application ballot for first subclass 462 from these countries. Pay registration fee, await selection email, then lodge within 28 days if selected. Not selected ≠ visa refusal — may register in future rounds."},{"id":"proof_of_sufficient_funds_for_initial_stay_typic","name":"Proof of sufficient funds for initial stay (typically AUD $5,000+ or equivalent)","mandatory":true,"notes":"Bank statements showing consistent balance; explain large recent deposits."},{"id":"return_onward_travel_evidence_or_funds_to_purcha","name":"Return/onward travel evidence or funds to purchase departure ticket","mandatory":true,"notes":"Officer must be satisfied applicant can support stay and depart Australia."},{"id":"brief_travel_work_plan_holiday_intent_regions_ti","name":"Brief travel / work plan (holiday intent, regions, timeline)","mandatory":false,"notes":"WHM is primarily holiday with incidental work — not full-time employment pathway."},{"id":"employment_study_ties_to_home_country_documented","name":"Employment / study ties to home country documented","mandatory":false,"notes":"Strengthens genuine temporary entrant assessment."},{"id":"adequate_health_insurance_for_entire_stay_in_aus","name":"Adequate health insurance for entire stay in Australia","mandatory":true,"notes":"Overseas Visitor Health Cover (OVHC) or equivalent acceptable policy — verify current Home Affairs guidance."},{"id":"client_briefed_on_whm_work_restrictions_6_month_","name":"Client briefed on WHM work restrictions (6-month employer limit, etc.)","mandatory":true,"notes":"Condition 8547 — generally cannot work for same employer more than 6 months unless exempt work."},{"id":"client_briefed_on_study_limit_generally_up_to_4_","name":"Client briefed on study limit (generally up to 4 months study)","mandatory":true},{"id":"government_visa_fee_paid_official_receipt_saved_","name":"Government visa fee paid; official receipt saved on file","mandatory":true,"notes":"Separate consultancy fee on invoice. Never commingle with government payment."},{"id":"client_reviewed_signed_and_dated_this_checklist","name":"Client reviewed, signed, and dated this checklist","mandatory":true},{"id":"quality_review_qa_sign_off_eligibility_funds_and","name":"Quality review / QA sign-off — eligibility, funds, and forms cross-checked","mandatory":true},{"id":"application_lodged_immiaccount_confirmation_trn_","name":"Application lodged; ImmiAccount confirmation / TRN saved on client file","mandatory":true}]'::jsonb, '[{"id":"passport_eligibility_identity","section_key":"passport_eligibility_identity","label":"Passport eligibility & identity","sort_order":0,"item_ids":["valid_passport_from_eligible_working_holiday_cou","applicant_age_within_limit_generally_18_30_up_to","first_working_holiday_maker_whm_visa_no_prior_wh","valid_passport_bio_page_previous_australian_visa","digital_photo_per_home_affairs_immiaccount_speci","not_accompanied_by_dependent_children_at_any_tim"]},{"id":"application_immiaccount","section_key":"application_immiaccount","label":"Application & ImmiAccount","sort_order":1,"item_ids":["immiaccount_created_and_online_whm_application_s","462_ballot_registration_completed_if_required_in"]},{"id":"financial_capacity_genuine_visitor","section_key":"financial_capacity_genuine_visitor","label":"Financial capacity & genuine visitor","sort_order":2,"item_ids":["proof_of_sufficient_funds_for_initial_stay_typic","return_onward_travel_evidence_or_funds_to_purcha","brief_travel_work_plan_holiday_intent_regions_ti","employment_study_ties_to_home_country_documented"]},{"id":"health_insurance_compliance","section_key":"health_insurance_compliance","label":"Health insurance & compliance","sort_order":3,"item_ids":["adequate_health_insurance_for_entire_stay_in_aus","client_briefed_on_whm_work_restrictions_6_month_","client_briefed_on_study_limit_generally_up_to_4_"]},{"id":"fees_qa_lodgement","section_key":"fees_qa_lodgement","label":"Fees, QA & lodgement","sort_order":4,"item_ids":["government_visa_fee_paid_official_receipt_saved_","client_reviewed_signed_and_dated_this_checklist","quality_review_qa_sign_off_eligibility_funds_and","application_lodged_immiaccount_confirmation_trn_"]}]'::jsonb);

