 to verify before submit","sort_order":2,"item_ids":["principal_applicant_not_eligible","weak_relationship_proof","recent_marriage_before_filing","prior_refusals_not_disclosed"]},{"id":"fees_submission","section_key":"fees_submission","label":"Fees & submission","sort_order":3,"item_ids":["government_visa_fee_paid_official_receipt_saved","client_reviewed_signed_and_dated_this_checklist","application_lodged_confirmation_reference_number"]}]'::jsonb);

