DELETE FROM public.workflow_templates WHERE category = 'c35e6051-f40f-47bf-9cac-0a386c47a336::Canada';
INSERT INTO public.workflow_templates (name, country, category, version, items, groups)
VALUES ('Canada Student Visa — Document binder', 'Canada', 'c35e6051-f40f-47bf-9cac-0a386c47a336::Canada', 1, '[{"id":"valid_passport_bio_data_page_any_previously_issu","name":"Valid passport — bio data page + any previously issued Canadian visa pages","mandatory":true,"notes":"Must be valid for at least 6 months beyond intended stay; upload colour scan."},{"id":"digital_photo_ircc_specifications_420_540_px_whi","name":"Digital photo — IRCC specifications (420 × 540 px, white background, neutral expression)","mandatory":true,"notes":"File must be a recent photo, ≤ 4 MB, JPEG format. Check IRCC photo tool at canada.ca."},{"id":"ircc_online_profile_complete_imm_5257_online_app","name":"IRCC online profile complete — IMM 5257 / online application signed & reviewed","mandatory":true,"notes":"All questions answered, no blanks; use \"NA\" where applicable. Review for consistency with supporting documents."},{"id":"original_letter_of_acceptance_loa_program_name_s","name":"Original Letter of Acceptance (LOA) — program name, start/end dates, tuition amount","mandatory":true,"notes":"LOA must be from a Designated Learning Institution (DLI). Conditional acceptance requires conditions met before travel."},{"id":"dli_number_verified_against_ircc_s_official_dli_","name":"DLI number verified against IRCC''s official DLI list at canada.ca","mandatory":true,"notes":"DLI status can change; confirm the institution remains active at time of submission."},{"id":"program_start_date_allows_realistic_ircc_process","name":"Program start date allows realistic IRCC processing time","mandatory":true,"notes":"Current processing times vary by visa office. Plan for 8–16 weeks. Defer intake if needed."},{"id":"proof_of_living_funds_at_least_cad_22_895_sep_20","name":"Proof of living funds: at least CAD $22,895 (Sep 2025 threshold) + first-year tuition + travel","mandatory":true,"notes":"Updated threshold effective Sept 1 2025. Add ~$4,000/dependent if bringing family."},{"id":"gic_from_participating_canadian_financial_instit","name":"GIC from participating Canadian financial institution — verify current amount","mandatory":false,"notes":"GIC still accepted as proof of funds. Confirm amount with institution at purchase."},{"id":"proof_of_first_year_tuition_payment_or_payment_a","name":"Proof of first-year tuition payment (or payment arrangement with institution)","mandatory":true,"notes":"Receipt from institution or bank transfer record required."},{"id":"language_test_result_trf_ielts_celpip_pte_tef_da","name":"Language test result (TRF) — IELTS / CELPIP / PTE / TEF / DALF as required by institution","mandatory":true,"notes":"Confirm required test & score with institution. IELTS/TEF also required for PGWP at post-graduation stage."},{"id":"degrees_diplomas_originals_and_copies_certified_","name":"Degrees / diplomas — originals and copies; certified translations where applicable","mandatory":true,"notes":"Credential evaluations (e.g. WES) may be required by institution, not IRCC."},{"id":"statement_of_purpose_sop_study_plan_genuine_stud","name":"Statement of Purpose (SOP) / Study Plan — genuine student intent & career pathway","mandatory":true,"notes":"Address why Canada, why this program, ties to home country. Must be original, not a template."},{"id":"confirm_program_is_pgwp_eligible_verify_on_ircc_","name":"Confirm program is PGWP-eligible — verify on IRCC list at canada.ca","mandatory":true,"notes":"Bachelor''s, Master''s, PhD remain eligible. Private colleges licensing public curriculum are NOT PGWP-eligible."},{"id":"upfront_medical_examination_ircc_designated_pane","name":"Upfront medical examination — IRCC-designated panel physician where required","mandatory":true,"notes":"Required if studying 6+ months AND from/residing 6+ months in a designated country."},{"id":"study_permit_application_fee_paid_cad_150_receip","name":"Study permit application fee paid — CAD $150; receipt saved","mandatory":true,"notes":"Pay via IRCC secure payment portal. Save transaction ID."},{"id":"biometrics_fee_paid_cad_85_170_family_receipt_sa","name":"Biometrics fee paid — CAD $85 / $170 family; receipt saved","mandatory":true,"notes":"Confirm exemption in IRCC account before paying if biometrics on file."},{"id":"client_reviewed_signed_and_dated_this_checklist","name":"Client reviewed, signed, and dated this checklist","mandatory":true,"notes":"Verify no expired documents, certified translations, form consistency."},{"id":"application_submitted_via_ircc_online_account_co","name":"Application submitted via IRCC online account; confirmation saved","mandatory":true,"notes":"Save screenshot, UCI, and application number for tracking."}]'::jsonb, '[{"id":"identity_travel_documents","section_key":"identity_travel_documents","label":"Identity & travel documents","sort_order":0,"item_ids":["valid_passport_bio_data_page_any_previously_issu","digital_photo_ircc_specifications_420_540_px_whi","ircc_online_profile_complete_imm_5257_online_app"]},{"id":"letter_of_acceptance_dli_pal_tal","section_key":"letter_of_acceptance_dli_pal_tal","label":"Letter of acceptance, DLI & PAL/TAL","sort_order":1,"item_ids":["original_letter_of_acceptance_loa_program_name_s","dli_number_verified_against_ircc_s_official_dli_","program_start_date_allows_realistic_ircc_process"]},{"id":"financial_proof","section_key":"financial_proof","label":"Financial proof","sort_order":2,"item_ids":["proof_of_living_funds_at_least_cad_22_895_sep_20","gic_from_participating_canadian_financial_instit","proof_of_first_year_tuition_payment_or_payment_a"]},{"id":"language_academic_documents","section_key":"language_academic_documents","label":"Language & academic documents","sort_order":3,"item_ids":["language_test_result_trf_ielts_celpip_pte_tef_da","degrees_diplomas_originals_and_copies_certified_","statement_of_purpose_sop_study_plan_genuine_stud"]},{"id":"pgwp_eligibility_check_post_graduation_work_perm","section_key":"pgwp_eligibility_check_post_graduation_work_perm","label":"PGWP eligibility check (post-graduation work permit)","sort_order":4,"item_ids":["confirm_program_is_pgwp_eligible_verify_on_ircc_"]},{"id":"medical_biometrics_police_certificates","section_key":"medical_biometrics_police_certificates","label":"Medical, biometrics & police certificates","sort_order":5,"item_ids":["upfront_medical_examination_ircc_designated_pane"]},{"id":"fees_submission","section_key":"fees_submission","label":"Fees & submission","sort_order":6,"item_ids":["study_permit_application_fee_paid_cad_150_receip","biometrics_fee_paid_cad_85_170_family_receipt_sa","client_reviewed_signed_and_dated_this_checklist","application_submitted_via_ircc_online_account_co"]}]'::jsonb);

