 consultancy fee on invoice. Never commingle with government payment."},{"id":"client_reviewed_signed_and_dated_this_checklist","name":"Client reviewed, signed, and dated this checklist","mandatory":true,"notes":"Verify expiry dates, translations, and consistency across forms."},{"id":"application_lodged_confirmation_reference_number","name":"Application lodged; confirmation / reference number saved on file","mandatory":true,"notes":"Screenshot portal confirmation and note tracking details for client."}]'::jsonb, '[{"id":"identity_travel_documents","section_key":"identity_travel_documents","label":"Identity & travel documents","sort_order":0,"item_ids":["valid_passport_bio_page_and_relevant_visa_stamp_","passport_size_photographs_per_embassy_online_por"]},{"id":"eligibility_core_documents","section_key":"eligibility_core_documents","label":"Eligibility & core documents","sort_order":1,"item_ids":["valid_passport","clear_temporary_purpose","strong_ties_to_india","proof_of_funds_for_trip","ds_160_completed_accurately"]},{"id":"common_issues_to_verify_before_submit","section_key":"common_issues_to_verify_before_submit","label":"Common issues to verify before submit","sort_order":2,"item_ids":["weak_ties_to_india","214_b_immigrant_intent_signals","ds_160_inconsistencies","prior_refusals_unchanged"]},{"id":"fees_submission","section_key":"fees_submission","label":"Fees & submission","sort_order":3,"item_ids":["government_visa_fee_paid_official_receipt_saved","client_reviewed_signed_and_dated_this_checklist","application_lodged_confirmation_reference_number"]}]'::jsonb);
